document.addEventListener("DOMContentLoaded",()=>{const n=document.getElementById("openMenu"),e=document.getElementById("menuOverlay"),s=document.getElementById("closeMenu");n&&e&&s&&(n.addEventListener("click",()=>{e.classList.add("active")}),s.addEventListener("click",()=>{e.classList.remove("active")}),e.addEventListener("click",t=>{t.target.tagName==="A"&&e.classList.remove("active")}));const t=document.querySelector(".header");if(t){const n=t.querySelector(".logo"),e=()=>{window.scrollY>50?t.classList.add("small"):t.classList.remove("small")};window.addEventListener("scroll",e),e()}})